Patch Set 13:

basically this is the patch I am having to do on top of this one to make it sort of work:

 diff --git a/lustre/ptlrpc/service.c b/lustre/ptlrpc/service.c
 index abac5b8..8ed45e8 100644
 --- a/lustre/ptlrpc/service.c
 +++ b/lustre/ptlrpc/service.c
 @@ -2464,17 +2464,20 @@ static void ptlrpc_watchdog_fire(struct work_struct *w)
  	struct ptlrpc_thread *thread = container_of(w, struct ptlrpc_thread,
  						    t_watchdog.work);
  	u64 ms_lapse = ktime_us_delta(ktime_get(), thread->t_touched);
 +	u32 ms_remainder;
 +
 +	ms_remainder = do_div(ms_lapse, MSEC_PER_SEC);

  	if (__ratelimit(&watchdog_limit)) {
 -		LCONSOLE_WARN("%s: service thread pid %u was inactive for %u.%.02llu seconds. The thread might be hung, or it might only be slow and will resume later. Dumping the stack trace for debugging purposes:\n",
 +		LCONSOLE_WARN("%s: service thread pid %u was inactive for %llu.%.02u seconds. The thread might be hung, or it might only be slow and will resume later. Dumping the stack trace for debugging purposes:\n",
  			      thread->t_task->comm, thread->t_task->pid,
 -			      do_div(ms_lapse, MSEC_PER_SEC), ms_lapse % MSEC_PER_SEC);
 +			      ms_lapse, ms_remainder);

  		libcfs_debug_dumpstack(thread->t_task);
  	} else {
 -		LCONSOLE_WARN("%s: service thread pid %u was inactive for %u.%.02llu seconds. Watchdog stack traces are limited to 3 per %u seconds, skipping this one.\n",
 +		LCONSOLE_WARN("%s: service thread pid %u was inactive for %llu.%.02u seconds. Watchdog stack traces are limited to 3 per %u seconds, skipping this one.\n",
  			      thread->t_task->comm, thread->t_task->pid,
 -			      do_div(ms_lapse, MSEC_PER_SEC), ms_lapse % MSEC_PER_SEC,
 +			      ms_lapse, ms_remainder,
  			      libcfs_watchdog_ratelimit);
  	}
  }
